/**
 * @file oled_ui.h
 * @brief OLED 显示 UI 组件：帧率测试 + 串口压力测试显示
 * @author
 * @date 2026-06-25
 *
 * @note 本模块封装两个功能：
 *       1. OLED_UI_FpsTick() — 帧率显示，替代 task_oled.c 中的手写循环
 *       2. OLED_UI_ShowStressTest() — 串口回环压力测试结果显示
 *
 *       两者独立，使用者按需调用。每次调用独占全屏。
 */

#ifndef __OLED_UI_H__
#define __OLED_UI_H__

/*==============================================================================
 * 头文件包含
 *============================================================================*/
#include <stdint.h>

/*==============================================================================
 * FPS 帧率显示
 *============================================================================*/
/**
 * @brief 初始化 FPS 计数器（每次复位后调用一次）
 */
void OLED_UI_FpsInit(void);

/**
 * @brief FPS 帧率刷新（按实际调用频率计算 FPS）
 * @note 内部调用 OLED_NewFrame + 绘图 + OLED_ShowFrame，
 *       每次调用独占全屏，不要在外层重复调用这些函数。
 *       建议放在主循环中调用，osDelay(1) 间隔。
 */
void OLED_UI_FpsTick(void);

#endif /* __OLED_UI_H__ */
